const express = require('express');
const router = express.Router();
const registroController = require('../controllers/registroController');
const { authenticate } = require('../middlewares/auth.middleware');
const { allowRoles } = require('../middlewares/role.middleware');
const { validateScan, validateManual, validateList } = require('../validators/registro.validator');

/**
 * POST /api/registro/scan
 * Escanear QR para registrar entrada/salida
 * Permitido para: guarda, administrador
 */
router.post('/scan', authenticate, allowRoles(['guarda', 'administrador']), validateScan, registroController.scanQR);

/**
 * POST /api/registro/manual
 * Registro manual por identificación
 * Permitido para: guarda, administrador
 */
router.post('/manual', authenticate, allowRoles(['guarda', 'administrador']), validateManual, registroController.registroManual);

/**
 * GET /api/registro
 * Listar registros con filtros y paginación
 * Permitido para: administrador, instructor, guarda
 */
router.get('/', authenticate, allowRoles(['administrador', 'instructor', 'guarda']), validateList, registroController.listarRegistros);

/**
 * GET /api/registro/last/:usuarioId
 * Obtener último estado de un usuario
 * Permitido para: administrador, instructor, guarda
 */
router.get('/last/:usuarioId', authenticate, allowRoles(['administrador', 'instructor', 'guarda']), registroController.obtenerUltimoEstado);

module.exports = router;
